import subprocess

def extract_tar_file(tar_path, dest_dir):
    try:
        subprocess.run(['tar', '-xvf', tar_path, '-C', dest_dir], check=True)
        print(f"Tar file extracted to {dest_dir}")
    except subprocess.CalledProcessError as e:
        print(f"Failed to extract tar file: {e}")

# Example usage
extract_tar_file('example.tar.gz', '/path/to/destination')